def sanitize_sensitive_data(data):
    """Sanitize sensitive data before logging"""
    if not isinstance(data, dict):
        return data
    
    sanitized = data.copy()
    sensitive_fields = ['password', 'token', 'api_key', 'secret', 'authorization']
    
    for key in sanitized:
        if any(field in key.lower() for field in sensitive_fields):
            sanitized[key] = '[REDACTED]'
    
    return sanitized


def log_request_info():
    """Log incoming request information"""
    app.logger.info(f"=== Incoming Request ===")
    app.logger.info(f"Method: {request.method}")
    app.logger.info(f"URL: {request.url}")
    app.logger.info(f"Path: {request.path}")
    app.logger.info(f"Remote Address: {request.remote_addr}")
    app.logger.info(f"User Agent: {request.user_agent}")
    
    # Log headers (sanitized)
    headers_dict = dict(request.headers)
    sanitized_headers = sanitize_sensitive_data(headers_dict)
    app.logger.info(f"Headers: {json.dumps(sanitized_headers, indent=2)}")
    
    # Log query parameters
    if request.args:
        app.logger.info(f"Query Parameters: {json.dumps(dict(request.args), indent=2)}")
    
    # Log request body (sanitized)
    if request.is_json:
        try:
            body_data = request.get_json()
            sanitized_body = sanitize_sensitive_data(body_data)
            app.logger.info(f"Request Body (JSON): {json.dumps(sanitized_body, indent=2)}")
        except Exception as e:
            app.logger.error(f"Error parsing JSON body: {str(e)}")
    elif request.form:
        sanitized_form = sanitize_sensitive_data(dict(request.form))
        app.logger.info(f"Form Data: {json.dumps(sanitized_form, indent=2)}")
    elif request.data:
        app.logger.info(f"Raw Data: {request.data[:500]}")


def log_response_info(response):
    """Log outgoing response information"""
    app.logger.info(f"=== Outgoing Response ===")
    app.logger.info(f"Status Code: {response.status_code}")
    app.logger.info(f"Response Headers: {json.dumps(dict(response.headers), indent=2)}")
    
    try:
        if response.is_json:
            response_data = response.get_json()
            app.logger.info(f"Response Body: {json.dumps(response_data, indent=2)}")
        else:
            app.logger.info(f"Response Data: {response.get_data(as_text=True)[:500]}")
    except Exception as e:
        app.logger.error(f"Error logging response: {str(e)}")
    
    return response


@app.before_request
def before_request():
    """Execute before each request"""
    g.start_time = datetime.now()
    log_request_info()


@app.after_request
def after_request(response):
    """Execute after each request"""
    if hasattr(g, 'start_time'):
        elapsed = (datetime.now() - g.start_time).total_seconds()
        app.logger.info(f"Request completed in {elapsed:.4f} seconds")
    
    return log_response_info(response)


@app.errorhandler(Exception)
def handle_exception(e):
    """Handle all exceptions"""
    app.logger.error(f"=== Exception Occurred ===")
    app.logger.error(f"Exception Type: {type(e).__name__}")
    app.logger.error(f"Exception Message: {str(e)}")
    app.logger.error(f"Traceback:\n{traceback.format_exc()}")
    
    return jsonify({
        'error': 'Internal Server Error',
        'message': str(e)
    }), 500


def require_auth(f):
    """Authentication decorator"""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization')
        
        if not auth_header:
            app.logger.warning("Authentication failed: No authorization header")
            return jsonify({'error': 'No authorization header'}), 401
        
        app.logger.info(f"Authentication attempt with header: {auth_header}")
        
        # Simple token validation (replace with actual validation)
        if not auth_header.startswith('Bearer '):
            app.logger.warning("Authentication failed: Invalid authorization format")
            return jsonify({'error': 'Invalid authorization format'}), 401
        
        token = auth_header.split(' ')[1]
        app.logger.debug(f"Validating token: {token}")
        
        # Add actual token validation here
        if token != 'valid_token_123':
            app.logger.warning(f"Authentication failed: Invalid token - {token}")
            return jsonify({'error': 'Invalid token'}), 401
        
        app.logger.info("Authentication successful")
        return f(*args, **kwargs)
    
    return decorated_function


